// src/pages/TrafficLayer.jsx
import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, LayerGroup, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import api from '../services/api';
import WebSocketService from '../services/WebSocketService';

// Fix Leaflet default marker icons
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconUrl: markerIcon,
  iconRetinaUrl: markerIcon2x,
  shadowUrl: markerShadow,
});

// Fit map bounds helper
const FitBounds = ({ vehicles }) => {
  const map = useMap();
  React.useEffect(() => {
    if (vehicles.length > 0) {
      const bounds = L.latLngBounds(vehicles.map(v => [v.lat, v.lng]));
      map.fitBounds(bounds, { padding: [50, 50] });
    }
  }, [vehicles, map]);
  return null;
};

// Custom icon by vehicle status
const getIconByStatus = (status) => {
  let colorUrl;
  switch (status) {
    case 'ACTIVE':
      colorUrl = 'https://chart.googleapis.com/chart?chst=d_map_pin_icon&chld=car|00FF00'; // green
      break;
    case 'IDLE':
      colorUrl = 'https://chart.googleapis.com/chart?chst=d_map_pin_icon&chld=car|FFFF00'; // yellow
      break;
    case 'MAINTENANCE':
      colorUrl = 'https://chart.googleapis.com/chart?chst=d_map_pin_icon&chld=car|FF0000'; // red
      break;
    default:
      colorUrl = markerIcon;
  }

  return new L.Icon({
    iconUrl: colorUrl,
    shadowUrl: markerShadow,
    iconSize: [30, 50],
    iconAnchor: [15, 50],
    popupAnchor: [0, -45],
    shadowSize: [41, 41],
  });
};

const TrafficLayer = () => {
  const [showTraffic, setShowTraffic] = useState(true);
  const [vehicles, setVehicles] = useState([]);
  const [vehicleStats, setVehicleStats] = useState({ active: 0, idle: 0, maintenance: 0 });
  const [loading, setLoading] = useState(true);

  // Fetch vehicles from API
  const fetchVehicles = async () => {
    try {
      const response = await api.get('/vehicles');
      const data = response.data;
      setVehicles(data);
      updateVehicleStats(data);
    } catch (err) {
      console.error('Error fetching vehicles:', err);
    } finally {
      setLoading(false);
    }
  };

  // Update stats
  const updateVehicleStats = (data) => {
    setVehicleStats({
      active: data.filter(v => v.status === 'ACTIVE').length,
      idle: data.filter(v => v.status === 'IDLE').length,
      maintenance: data.filter(v => v.status === 'MAINTENANCE').length,
    });
  };

  useEffect(() => {
    fetchVehicles();

    // Connect to WebSocket
    WebSocketService.connect();
    WebSocketService.subscribe('/topic/vehicles', (message) => {
      const vehicleData = JSON.parse(message.body);
      setVehicles(prev => {
        const updated = [...prev.filter(v => v.id !== vehicleData.id), vehicleData];
        updateVehicleStats(updated);
        return updated;
      });
    });

    return () => WebSocketService.disconnect();
  }, []);

  return (
    <div className="space-y-6">
      <h2 className="g-title">Traffic Layer</h2>
      <div className="flex space-x-4 mb-4">
        <button className="g-btn" onClick={() => setShowTraffic(!showTraffic)}>
          {showTraffic ? 'Hide Traffic' : 'Show Traffic'}
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Map */}
        <div className="lg:col-span-2 stat-card">
          <h3 className="text-lg font-semibold mb-4">Traffic Map</h3>
          {loading ? (
            <p className="text-gray-600">Loading map...</p>
          ) : (
            <MapContainer
              center={[20.5937, 78.9629]}
              zoom={5}
              className="w-full h-[600px] rounded-lg shadow-md"
            >
              <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a> contributors'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              />
              <FitBounds vehicles={vehicles} />
              {showTraffic && (
                <LayerGroup>
                  {vehicles.map(v => (
                    <Marker key={v.id} position={[v.lat, v.lng]} icon={getIconByStatus(v.status)}>
                      <Popup>
                        🚗 Vehicle {v.id} <br /> Status: {v.status}
                      </Popup>
                    </Marker>
                  ))}
                </LayerGroup>
              )}
            </MapContainer>
          )}
        </div>

        {/* Vehicle Stats */}
        <div className="stat-card">
          <h3 className="text-lg font-semibold mb-4">Vehicle Status Summary</h3>
          {loading ? (
            <p className="text-gray-600">Loading stats...</p>
          ) : (
            <div className="space-y-2">
              <p className="bg-blue-100 p-2 rounded">Active: {vehicleStats.active}</p>
              <p className="bg-yellow-100 p-2 rounded">Idle: {vehicleStats.idle}</p>
              <p className="bg-red-100 p-2 rounded">Maintenance: {vehicleStats.maintenance}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TrafficLayer;
